export default function DocumentActions() {
  const [docs, setDocs] = useState([]);
  const [selected, setSelected] = useState("");
  const [action, setAction] = useState("verify");
  const [reason, setReason] = useState("");
  const [fileName, setFileName] = useState("");
  const [phase, setPhase] = useState("idle");
  const [message, setMessage] = useState("");

  useEffect(() => {
    tools.host_listClientDocuments({ id: "1" }).then((r) => setDocs(r.data || []));
  }, []);

  const actionable = docs.filter((d) => d.status === "received" || d.status === "needs_review");

  const submit = async () => {
    if (!selected) return;
    setPhase("sending");
    const body = { action };
    if (action === "receive") body.fileName = fileName;
    if (action === "reject") body.reason = reason;
    const result = await tools.host_setDocumentStatus({ id: "1", docId: selected, body });
    if (result && result.status === "pending-approval") {
      setPhase("awaiting");
      setMessage("Action submitted — awaiting approval.");
    } else {
      setPhase("done");
      setMessage("Document status updated.");
    }
  };

  const labelFor = (a) => ({ verify: "Verify", reject: "Reject", receive: "Mark received" }[a] || a);

  return (
    <div style={{
      background: "var(--vendo-color-surface)",
      border: "1px solid var(--vendo-color-border)",
      borderRadius: "var(--vendo-radius-medium)",
      padding: 20,
      display: "grid",
      gap: 14,
      fontFamily: "var(--vendo-font-family)",
      fontSize: 14,
      color: "var(--vendo-color-text)"
    }}>
      <div style={{ fontWeight: 600, fontSize: 15 }}>Update a document</div>

      {actionable.length === 0 && (
        <div style={{ color: "var(--vendo-color-muted)" }}>No documents currently awaiting verification or rejection.</div>
      )}

      {actionable.length > 0 && (
        <>
          <div style={{ display: "grid", gap: 6 }}>
            <label style={{ fontSize: 13, color: "var(--vendo-color-muted)" }}>Document</label>
            <select
              value={selected}
              onChange={(e) => setSelected(e.target.value)}
              style={{
                padding: "8px 10px",
                borderRadius: "var(--vendo-radius-small)",
                border: "1px solid var(--vendo-color-border)",
                background: "var(--vendo-color-background)",
                color: "var(--vendo-color-text)",
                fontFamily: "var(--vendo-font-family)",
                fontSize: 14
              }}
            >
              <option value="">Choose a document…</option>
              {actionable.map((d) => (
                <option key={d.id} value={d.id}>{d.name} — {d.status}</option>
              ))}
            </select>
          </div>

          <div style={{ display: "grid", gap: 6 }}>
            <label style={{ fontSize: 13, color: "var(--vendo-color-muted)" }}>Action</label>
            <select
              value={action}
              onChange={(e) => setAction(e.target.value)}
              style={{
                padding: "8px 10px",
                borderRadius: "var(--vendo-radius-small)",
                border: "1px solid var(--vendo-color-border)",
                background: "var(--vendo-color-background)",
                color: "var(--vendo-color-text)",
                fontFamily: "var(--vendo-font-family)",
                fontSize: 14
              }}
            >
              <option value="verify">Verify — mark as confirmed correct</option>
              <option value="reject">Reject — return to client with a note</option>
              <option value="receive">Mark received — attach a file name</option>
            </select>
          </div>

          {action === "reject" && (
            <div style={{ display: "grid", gap: 6 }}>
              <label style={{ fontSize: 13, color: "var(--vendo-color-muted)" }}>Reason shown to client</label>
              <textarea
                value={reason}
                onChange={(e) => setReason(e.target.value)}
                rows={3}
                placeholder="Explain what needs to be corrected…"
                style={{
                  padding: "8px 10px",
                  borderRadius: "var(--vendo-radius-small)",
                  border: "1px solid var(--vendo-color-border)",
                  background: "var(--vendo-color-background)",
                  color: "var(--vendo-color-text)",
                  fontFamily: "var(--vendo-font-family)",
                  fontSize: 14,
                  resize: "vertical"
                }}
              />
            </div>
          )}

          {action === "receive" && (
            <div style={{ display: "grid", gap: 6 }}>
              <label style={{ fontSize: 13, color: "var(--vendo-color-muted)" }}>File name</label>
              <input
                value={fileName}
                onChange={(e) => setFileName(e.target.value)}
                placeholder="e.g. W2_2025.pdf"
                style={{
                  padding: "8px 10px",
                  borderRadius: "var(--vendo-radius-small)",
                  border: "1px solid var(--vendo-color-border)",
                  background: "var(--vendo-color-background)",
                  color: "var(--vendo-color-text)",
                  fontFamily: "var(--vendo-font-family)",
                  fontSize: 14
                }}
              />
            </div>
          )}

          {message && (
            <div style={{
              padding: "10px 14px",
              borderRadius: "var(--vendo-radius-small)",
              background: phase === "awaiting" ? "#fef9ec" : "#f0faf4",
              color: phase === "awaiting" ? "#92600a" : "#1a6b3c",
              fontSize: 13
            }}>
              {message}
            </div>
          )}

          <button
            onClick={submit}
            disabled={!selected || phase === "sending" || phase === "awaiting" || phase === "done"}
            style={{
              padding: "9px 18px",
              borderRadius: "var(--vendo-radius-small)",
              background: "var(--vendo-color-accent)",
              color: "var(--vendo-color-accent-text)",
              border: "none",
              fontFamily: "var(--vendo-font-family)",
              fontSize: 14,
              fontWeight: 600,
              cursor: "pointer",
              opacity: (!selected || phase !== "idle") ? 0.5 : 1,
              justifySelf: "start"
            }}
          >
            {phase === "sending" ? "Submitting…" : phase === "awaiting" ? "Awaiting approval…" : phase === "done" ? "Done" : labelFor(action)}
          </button>
        </>
      )}
    </div>
  );
}

components.MessageThread:
export default function MessageThread() {
  const [messages, setMessages] = useState([]);
  const [body, setBody] = useState("");
  const [phase, setPhase] = useState("idle");
  const [sent, setSent] = useState(false);

  useEffect(() => {
    tools.host_listClientMessages({ id: "1" }).then((r) => setMessages(r.data || []));
  }, []);

  const send = async () => {
    if (!body.trim()) return;
    setPhase("sending");
    const result = await tools.host_sendClientMessage({ id: "1", body: { body: body.trim(), author: "firm" } });
    if (result && result.status === "pending-approval") {
      setPhase("awaiting");
    } else {
      setPhase("idle");
      setSent(true);
      setBody("");
      tools.host_listClientMessages({ id: "1" }).then((r) => setMessages(r.data || []));
    }
  };

  return (
    <div style={{
      display: "grid",
      gap: 16,
      fontFamily: "var(--vendo-font-family)",
      fontSize: 14,
      color: "var(--vendo-color-text)"
    }}>
      <div style={{
        display: "grid",
        gap: 10,
        maxHeight: 360,
        overflowY: "auto",
        padding: "4px 0"
      }}>
        {messages.length === 0 && (
          <div style={{ color: "var(--vendo-color-muted)", padding: "12px 0" }}>No messages yet — send one below to start the conversation.</div>
        )}
        {messages.map((m, i) => {
          const isFirm = m.author === "firm";
          return (
            <div key={m.id || i} style={{
              display: "grid",
              gap: 3,
              justifyItems: isFirm ? "end" : "start"
            }}>
              <div style={{
                maxWidth: "72%",
                padding: "10px 14px",
                borderRadius: "var(--vendo-radius-medium)",
                background: isFirm ? "var(--vendo-color-accent)" : "var(--vendo-color-surface)",
                color: isFirm ? "var(--vendo-color-accent-text)" : "var(--vendo-color-text)",
                border: isFirm ? "none" : "1px solid var(--vendo-color-border)",
                lineHeight: 1.5
              }}>
                {m.body}
              </div>
              <div style={{ fontSize: 12, color: "var(--vendo-color-muted)" }}>
                {isFirm ? "Firm" : "Client"}{m.sentAt ? ` · ${fmt.dateTime(m.sentAt)}` : ""}
              </div>
            </div>
          );
        })}
      </div>

      {sent && (
        <div style={{ fontSize: 13, color: "#1a6b3c" }}>Message sent.</div>
      )}
      {phase === "awaiting" && (
        <div style={{ fontSize: 13, color: "#92600a" }}>Message submitted — awaiting approval before delivery.</div>
      )}

      <div style={{ display: "grid", gap: 8 }}>
        <textarea
          value={body}
          onChange={(e) => setBody(e.target.value)}
          rows={3}
          placeholder="Write a message to the client…"
          disabled={phase === "awaiting"}
          style={{
            padding: "10px 12px",
            borderRadius: "var(--vendo-radius-small)",
            border: "1px solid var(--vendo-color-border)",
            background: "var(--vendo-color-background)",
            color: "var(--vendo-color-text)",
            fontFamily: "var(--vendo-font-family)",
            fontSize: 14,
            resize: "vertical"
          }}
        />
        <button
          onClick={send}
          disabled={!body.trim() || phase !== "idle"}
          style={{
            padding: "9px 18px",
            borderRadius: "var(--vendo-radius-small)",
            background: "var(--vendo-color-accent)",
            color: "var(--vendo-color-accent-text)",
            border: "none",
            fontFamily: "var(--vendo-font-family)",
            fontSize: 14,
            fontWeight: 600,
            cursor: "pointer",
            opacity: (!body.trim() || phase !== "idle") ? 0.5 : 1,
            justifySelf: "start"
          }}
        >
          {phase === "sending" ? "Sending…" : phase === "awaiting" ? "Awaiting approval…" : "Send message"}
        </button>
      </div>
    </div>
  );
}
